Bash(cd F:/Yamata/Presage && node -e "
const {ethers} = require\('ethers'\);
require\('dotenv'\).config\(\);
const provider = new ethers.JsonRpcProvider\(process.env.BNB_RPC_URL\);
const USDT = '0x55d398326f99059fF775485246999027B3197955';
const ERC20 = ['function balanceOf\(address\) view returns \(uint256\)'];

\(async \(\) => {
  const w1 = new ethers.Wallet\(process.env.WALLET_PRIVATE_KEY, provider\);
  const bnb1 = await provider.getBalance\(w1.address\);
  const usdt = new ethers.Contract\(USDT, ERC20, provider\);
  const usdt1 = await usdt.balanceOf\(w1.address\);
  console.log\('Wallet 1:', w1.address\);
  console.log\('  BNB :', ethers.formatEther\(bnb1\)\);
  console.log\('  USDT:', ethers.formatEther\(usdt1\)\);

  if \(process.env.WALLET_PRIVATE_KEY_2\) {
    const w2 = new ethers.Wallet\(process.env.WALLET_PRIVATE_KEY_2, provider\);
    const bnb2 = await provider.getBalance\(w2.address\);
    const usdt2 = await usdt.balanceOf\(w2.address\);
    console.log\('Wallet 2:', w2.address\);
    console.log\('  BNB :', ethers.formatEther\(bnb2\)\);
    console.log\('  USDT:', ethers.formatEther\(usdt2\)\);
  } else {
    console.log\('Wallet 2: not set \(will generate random\)'\);
  }

  const gasPrice = \(await provider.getFeeData\(\)\).gasPrice;
  console.log\('Gas price:', ethers.formatUnits\(gasPrice, 'gwei'\), 'gwei'\);
}\)\(\);
" 2>&1)

