const {ethers} = require\('ethers'\);
require\('dotenv'\).config\(\);
const provider = new ethers.JsonRpcProvider\(process.env.BNB_RPC_URL\);
\(async \(\) => {
  const receipt = await provider.getTransactionReceipt\('0x02d8dcd6b4d559cfd8e7c5b81d5eb4e68a5cd560791fb239bcdafc5c28f3de05'\);
  if \(receipt\) {
    console.log\('Status:', receipt.status === 1 ? 'SUCCESS' : 'FAILED'\);
    console.log\('Contract:', receipt.contractAddress\);
    console.log\('Gas used:', receipt.gasUsed.toString\(\)\);
    console.log\('Block:', receipt.blockNumber\);
  } else {
    console.log\('Transaction not yet mined or not found'\);
  }
}\)\(\);
" 2>&1)
